# List all resources in a catalog with their available roles
$catalogId = '<catalog-id>'
$resources = Invoke-MgGraphRequest -Method GET \
  -Uri "https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/catalogs/$catalogId/resources?`$expand=roles,scopes"

foreach ($r in $resources.value) {
    Write-Host "Resource: $($r.displayName) [$($r.originSystem)]"
    foreach ($role in $r.roles) {
        Write-Host "  Role: $($role.displayName) (id=$($role.id) originId=$($role.originId))"
    }
}

# Add a second policy to an existing access package
# This policy targets external users from a connected organization
$extPolicy = @{
    displayName     = 'External contractor policy'
    accessPackageId = '<package-id>'
    requestorSettings = @{
        scopeType      = 'SpecificConnectedOrganizationUsers'
        acceptRequests = $true
        allowedRequestors = @(
            @{ '@odata.type'       = '#microsoft.graph.connectedOrganizationMembers'
               connectedOrganizationId = '<connected-org-id>'
               isBackup = $false }
        )
    }
    requestApprovalSettings = @{
        isApprovalRequired = $true
        approvalMode       = 'Serial'
        approvalStages = @(
            @{ approvalStageTimeOutInDays = 7
               primaryApprovers = @( @{ '@odata.type' = '#microsoft.graph.requestorManager'; managerLevel = 1 } ) },
            @{ approvalStageTimeOutInDays = 5
               primaryApprovers = @( @{ '@odata.type' = '#microsoft.graph.singleUser'; id = '<resource-owner-oid>' } ) }
        )
    }
    expiration = @{ type = 'afterDuration'; duration = 'P30D' }
} | ConvertTo-Json -Depth 12

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/assignmentPolicies' \
  -Body $extPolicy -ContentType 'application/json'

# User submits a self-service request for a package
# Runs as the requesting user (delegated permission: EntitlementManagement.ReadWrite.All)
$req = @{
    requestType = 'userAdd'
    accessPackageAssignment = @{
        targetId           = '<requestor-user-oid>'
        assignmentPolicyId = '<policy-id>'
        accessPackageId    = '<package-id>'
    }
    justification = 'Need access to prod monitoring tools for incident response during on-call rotation Q1 2025'
    schedule = @{
        startDateTime = '2025-01-10T00:00:00Z'
        expiration    = @{ type = 'afterDuration'; duration = 'P30D' }
    }
} | ConvertTo-Json -Depth 8

$result = Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/assignmentRequests' \
  -Body $req -ContentType 'application/json'

Write-Host "Request ID: $($result.id)  State: $($result.state)"

# User submits an extension request for an existing assignment
$extReq = @{
    requestType = 'userExtend'
    accessPackageAssignment = @{
        id = '<existing-assignment-id>'
    }
    justification = 'Project extended by 60 days — need continued access to prod monitoring'
    schedule = @{
        expiration = @{ type = 'afterDuration'; duration = 'P60D' }
    }
} | ConvertTo-Json -Depth 6

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/assignmentRequests' \
  -Body $extReq -ContentType 'application/json'

# Admin can also extend on behalf of a user
$adminExt = @{
    requestType = 'adminExtend'
    accessPackageAssignment = @{ id = '<assignment-id>' }
    schedule = @{ expiration = @{ type = 'afterDuration'; duration = 'P30D' } }
} | ConvertTo-Json -Depth 6

// Entitlement Management activity — all events by type in last 30 days
AuditLogs
| where TimeGenerated > ago(30d)
| where LoggedByService == 'Entitlement Management'
| summarize Count=count() by OperationName
| order by Count desc

// Find packages with assignments expiring in the next 14 days
// Query this from Graph, not Log Analytics — use Graph API schedule filter
// In PowerShell:
// $soon = (Get-Date).AddDays(14).ToString('yyyy-MM-ddTHH:mm:ssZ')
// $Uri = "https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/assignments?`$filter=state eq 'Delivered' and schedule/expiration/endDateTime le $soon"

# Create a Lifecycle Workflow task to request an access package on joiner event
# Requires LifecycleWorkflows.ReadWrite.All
$workflowBody = @{
    displayName = 'New hire engineering onboarding'
    description = 'Assigns Engineering Bundle access package on hire date'
    category    = 'joiner'
    isEnabled   = $true
    isSchedulingEnabled = $true
    executionConditions = @{
        '@odata.type' = '#microsoft.graph.identityGovernance.triggerAndScopeBasedConditions'
        scope = @{
            '@odata.type' = '#microsoft.graph.identityGovernance.ruleBasedSubjectSet'
            rule = "(department eq 'Engineering')"
        }
        trigger = @{
            '@odata.type' = '#microsoft.graph.identityGovernance.timeBasedAttributeTrigger'
            timeBasedAttribute = 'employeeHireDate'
            offsetInDays       = 0
        }
    }
    tasks = @(
        @{
            displayName     = 'Request Engineering Bundle access package'
            category        = 'joiner'
            taskDefinitionId = '9f2e1b2a-76f0-4d9a-aacc-72fbf019e2c9'  # requestAccessPackageAssignment
            isEnabled       = $true
            arguments = @(
                @{ name = 'accessPackageId';    value = '<engineering-bundle-package-id>' },
                @{ name = 'assignmentPolicyId'; value = '<new-hire-policy-id>' }
            )
        }
    )
} | ConvertTo-Json -Depth 12

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/lifecycleWorkflows/workflows' \
  -Body $workflowBody -ContentType 'application/json'

# Add custom questions to an assignment policy
# Requires updating the policy with questions array
$policyPatch = @{
    questions = @(
        @{
            '@odata.type'    = '#microsoft.graph.accessPackageTextInputQuestion'
            sequence         = 1
            isRequired       = $true
            isAnswerEditable = $true
            text = @{
                defaultText       = 'What is the business justification for this access?'
                localizedTexts    = @()
            }
        },
        @{
            '@odata.type' = '#microsoft.graph.accessPackageMultipleChoiceQuestion'
            sequence      = 2
            isRequired    = $true
            text = @{ defaultText = 'Expected duration of need?' }
            choices = @(
                @{ actualValue = '30days';  displayValue = @{ defaultText = '30 days' } },
                @{ actualValue = '90days';  displayValue = @{ defaultText = '90 days' } },
                @{ actualValue = 'ongoing'; displayValue = @{ defaultText = 'Ongoing (requires review)' } }
            )
        }
    )
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method PATCH \
  -Uri "https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/assignmentPolicies/<policy-id>" \
  -Body $policyPatch -ContentType 'application/json'

# Retrieve answers from a submitted request
$req = Invoke-MgGraphRequest -Method GET \
  -Uri "https://graph.microsoft.com/v1.0/identityGovernance/entitlementManagement/assignmentRequests/<request-id>?`$expand=answers"

$req.answers | ForEach-Object { Write-Host "$($_.answeredQuestion.text.defaultText): $($_.value)" }
